package format

import (
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

// CompactDiffFormatter produces a condensed, summary-style diff output
// for terraform plan, showing only resource-level changes without
// attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a compact summary of changes in the plan, grouped by action type.
// It displays one line per resource change showing the action and resource address.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group changes by action type
	changesByAction := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)

	// Iterate through all resource changes, filtering out deposed objects
	for _, rc := range plan.Changes.Resources {
		// Skip deposed keys (only show current objects)
		if rc.DeposedKey != states.NotDeposed {
			continue
		}

		changesByAction[rc.Action] = append(changesByAction[rc.Action], rc)
	}

	var output strings.Builder

	// Define the order of actions to display
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Delete,
		plans.Read,
		plans.Forget,
		plans.CreateThenForget,
	}

	// Process each action type in order
	for _, action := range actionOrder {
		changes, ok := changesByAction[action]
		if !ok || len(changes) == 0 {
			continue
		}

		// Sort resources by address for consistent output
		sort.Slice(changes, func(i, j int) bool {
			return changes[i].Addr.String() < changes[j].Addr.String()
		})

		// Write action header
		actionLabel := actionLabel(action)
		output.WriteString(fmt.Sprintf("%s resources:\n", actionLabel))

		// Write each resource change
		for _, rc := range changes {
			resourceType := rc.Addr.Resource.Resource.Type
			resourceName := rc.Addr.Resource.Name

			// Build the full resource address
			var addr string
			if rc.Addr.Module.IsRoot() {
				addr = fmt.Sprintf("%s.%s", resourceType, resourceName)
			} else {
				addr = fmt.Sprintf("module.%s.%s.%s", strings.Join(rc.Addr.Module.Module().Names(), "."), resourceType, resourceName)
			}

			output.WriteString(fmt.Sprintf("  [%s] %s\n", actionSymbol(action), addr))
		}

		output.WriteString("\n")
	}

	// Write summary
	counts := countChanges(changesByAction)
	output.WriteString(fmt.Sprintf("Plan: %d to add, %d to change, %d to destroy\n",
		counts[plans.Create]+counts[plans.DeleteThenCreate]+counts[plans.CreateThenDelete]+counts[plans.CreateThenForget],
		counts[plans.Update],
		counts[plans.Delete]+counts[plans.DeleteThenCreate]+counts[plans.CreateThenDelete],
	))

	return output.String()
}

// actionLabel returns a human-readable label for an action type
func actionLabel(action plans.Action) string {
	switch action {
	case plans.Create, plans.CreateThenForget, plans.CreateThenDelete:
		return "Create"
	case plans.Update:
		return "Update"
	case plans.Delete, plans.DeleteThenCreate:
		return "Delete"
	case plans.Read:
		return "Read"
	case plans.Forget:
		return "Forget"
	case plans.NoOp:
		return "No-op"
	default:
		return "Unknown"
	}
}

// actionSymbol returns a short symbol for an action type
func actionSymbol(action plans.Action) string {
	switch action {
	case plans.Create:
		return "+"
	case plans.Delete:
		return "-"
	case plans.Update:
		return "~"
	case plans.DeleteThenCreate:
		return "-/+"
	case plans.CreateThenDelete:
		return "+/-"
	case plans.Read:
		return "<="
	case plans.Forget:
		return "."
	case plans.CreateThenForget:
		return "+/."
	default:
		return "?"
	}
}

// countChanges returns a map of action counts
func countChanges(changesByAction map[plans.Action][]*plans.ResourceInstanceChangeSrc) map[plans.Action]int {
	counts := make(map[plans.Action]int)
	for action, changes := range changesByAction {
		counts[action] = len(changes)
	}
	return counts
}

