)

func TestCompactDiffFormatterBasic(t *testing.T) {
	tests := map[string]struct {
		changes *plans.ChangesSrc
		want    string
	}{
		"empty plan": {
			changes: plans.NewChangesSrc(),
			want:    "",
		},
		"single create": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Create,
					},
				},
			},
			want: `Create resources:
  [+] aws_instance.example

Plan: 1 to add, 0 to change, 0 to destroy
`,
		},
		"single update": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Update,
					},
				},
			},
			want: `Update resources:
  [~] aws_instance.example

Plan: 0 to add, 1 to change, 0 to destroy
`,
		},
		"single delete": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Delete,
					},
				},
			},
			want: `Delete resources:
  [-] aws_instance.example

Plan: 0 to add, 0 to change, 1 to destroy
`,
		},
		"mixed changes": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Create,
					},
					{
						Addr:       makeAddr("aws_instance.updated"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Update,
					},
					{
						Addr:       makeAddr("aws_instance.deleted"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Delete,
					},
				},
			},
			want: `Create resources:
  [+] aws_instance.example

Update resources:
  [~] aws_instance.updated

Delete resources:
  [-] aws_instance.deleted

Plan: 1 to add, 1 to change, 1 to destroy
`,
		},
		"replace delete then create": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.DeleteThenCreate,
					},
				},
			},
			want: `Delete resources:
  [-/+] aws_instance.example

Plan: 1 to add, 0 to change, 1 to destroy
`,
		},
		"replace create then delete": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.CreateThenDelete,
					},
				},
			},
			want: `Delete resources:
  [+/-] aws_instance.example

Plan: 1 to add, 0 to change, 1 to destroy
`,
		},
		"skip deposed objects": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Create,
					},
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.DeposedKey("old"),
						Action:     plans.Delete,
					},
				},
			},
			want: `Create resources:
  [+] aws_instance.example

Plan: 1 to add, 0 to change, 0 to destroy
`,
		},
		"multiple creates sorted": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.zebra"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Create,
					},
					{
						Addr:       makeAddr("aws_instance.apple"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Create,
					},
					{
						Addr:       makeAddr("aws_instance.banana"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Create,
					},
				},
			},
			want: `Create resources:
  [+] aws_instance.apple
  [+] aws_instance.banana
  [+] aws_instance.zebra

Plan: 3 to add, 0 to change, 0 to destroy
`,
		},
		"read action": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("data.external.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Read,
					},
				},
			},
			want: `Read resources:
  [<=] data.external.example

Plan: 0 to add, 0 to change, 0 to destroy
`,
		},
		"forget action": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.Forget,
					},
				},
			},
			want: `Forget resources:
  [.] aws_instance.example

Plan: 0 to add, 0 to change, 0 to destroy
`,
		},
		"create then forget": {
			changes: &plans.ChangesSrc{
				Resources: []*plans.ResourceInstanceChangeSrc{
					{
						Addr:       makeAddr("aws_instance.example"),
						DeposedKey: states.NotDeposed,
						Action:     plans.CreateThenForget,
					},
				},
			},
			want: `Create resources:
  [+/.] aws_instance.example

Plan: 1 to add, 0 to change, 0 to destroy
`,
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			plan := &plans.Plan{
				Changes: tc.changes,
			}

			formatter := &CompactDiffFormatter{}
			got := formatter.Format(plan, &schemarepo.Schemas{})

			if diff := cmp.Diff(tc.want, got); diff != "" {
				t.Errorf("Format() output mismatch (-want +got):\n%s", diff)
			}
		})
	}
}

func TestCompactDiffFormatterNilPlan(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	result := formatter.Format(nil, &schemarepo.Schemas{})
	if result != "" {
		t.Errorf("Format(nil plan) expected empty string, got %q", result)
	}
}

func TestCompactDiffFormatterNilChanges(t *testing.T) {
	plan := &plans.Plan{
		Changes: nil,
	}
	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})
	if result != "" {
		t.Errorf("Format(plan with nil changes) expected empty string, got %q", result)
	}
}

// Helper function to create a resource address
func makeAddr(resourceAddr string) addrs.AbsResourceInstance {
	// Parse simple resource addresses like "aws_instance.example" or "data.external.example"
	addr, diags := addrs.ParseAbsResourceInstanceStr(resourceAddr)
	if diags.HasErrors() {
		panic("invalid test resource address: " + resourceAddr)
	}
	return addr
}

